module top_module(
    input clk,
    input reset,
    output reg [3:0] bit_0,
    output reg [3:0] bit_1,
    output reg [3:0] bit_2,
    output reg [3:0] bit_3
);reg [3:0] obf_counter;

always @(posedge clk) begin
    if (reset) begin
        obf_counter <= 4'b0000;
    end else begin
        obf_counter <= {obf_counter[2:0], obf_counter[3]};
    end
end

assign bit_0 = obf_counter[0];
assign bit_1 = obf_counter[1];
assign bit_2 = obf_counter[2];
assign bit_3 = obf_counter[3];

endmodule
